const BASE_URL = 'http://4.237.58.241:3000';

const getAuthHeader = () => {
  const token = localStorage.getItem('token');

  return token
    ? { Authorization: `Bearer ${token}` }
    : {};
};

const handleResponse = async (res) => {
  const data = await res.json();

  if (!res.ok) {
    throw new Error(
      data.message || data.error || `HTTP ${res.status}`
    );
  }

  return data;
};

// ─── Rentals ────────────────────────────────────────────────────────────────

export const fetchStates = async () => {
  const res = await fetch(`${BASE_URL}/rentals/states`);
  const data = await handleResponse(res);

  // Always return array
  return Array.isArray(data)
    ? data
    : data.data || [];
};

export const fetchPropertyTypes = async () => {
  const res = await fetch(`${BASE_URL}/rentals/propertyType`);
  const data = await handleResponse(res);

  // Always return array
  return Array.isArray(data)
    ? data
    : data.data || [];
};

export const searchRentals = async (params = {}) => {
  const query = new URLSearchParams();

  Object.entries(params).forEach(([k, v]) => {
    if (
      v !== '' &&
      v !== null &&
      v !== undefined
    ) {
      query.append(k, v);
    }
  });

  const res = await fetch(
    `${BASE_URL}/rentals/search?${query}`
  );

  return handleResponse(res);
};

export const fetchRental = async (id) => {
  const res = await fetch(
    `${BASE_URL}/rentals/${id}`
  );

  return handleResponse(res);
};

// ─── Ratings ────────────────────────────────────────────────────────────────

export const fetchMyRatings = async (params = {}) => {
  const query = new URLSearchParams();

  Object.entries(params).forEach(([k, v]) => {
    if (
      v !== '' &&
      v !== null &&
      v !== undefined
    ) {
      query.append(k, v);
    }
  });

  const res = await fetch(
    `${BASE_URL}/ratings?${query}`,
    {
      headers: getAuthHeader(),
    }
  );

  return handleResponse(res);
};

export const fetchRatingForRental = async (id) => {
  const res = await fetch(
    `${BASE_URL}/ratings/rentals/${id}`,
    {
      headers: getAuthHeader(),
    }
  );

  return handleResponse(res);
};

export const postRating = async (id, rating) => {
  const res = await fetch(
    `${BASE_URL}/ratings/rentals/${id}`,
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...getAuthHeader(),
      },
      body: JSON.stringify({ rating }),
    }
  );

  return handleResponse(res);
};

// ─── Auth ────────────────────────────────────────────────────────────────────

export const register = async (email, password) => {
  const res = await fetch(
    `${BASE_URL}/user/register`,
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        email,
        password,
      }),
    }
  );

  return handleResponse(res);
};

export const login = async (email, password) => {
  const res = await fetch(
    `${BASE_URL}/user/login`,
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        email,
        password,
      }),
    }
  );

  const data = await handleResponse(res);

  if (data?.token) {
    localStorage.setItem('token', data.token);
  }

  return data;
};
